import React, { useEffect, useState } from "react";
import { auth, db } from "../firebase/config";
import {
  getDoc,
  doc,
  collection,
  query,
  onSnapshot,
  updateDoc,
} from "firebase/firestore";
import { signOut } from "firebase/auth";

export default function Dashboard({ user }) {
  const [orders, setOrders] = useState([]);
  const [status, setStatus] = useState("Unavailable");

  useEffect(() => {
    async function fetchShopStatus() {
      const shopRef = doc(db, "shopkeepers", user.uid);
      const snap = await getDoc(shopRef);
      if (snap.exists()) setStatus(snap.data().status || "Unavailable");
    }
    fetchShopStatus();
  }, [user.uid]);

  useEffect(() => {
    const ref = collection(db, "shopkeepers", user.uid, "print_requests");
    const q = query(ref);
    const unsub = onSnapshot(q, snapshot => {
      const list = snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
      setOrders(list);
    });
    return () => unsub();
  }, [user.uid]);

  const toggleStatus = async () => {
    const newStatus = status === "Available" ? "Unavailable" : "Available";
    await updateDoc(doc(db, "shopkeepers", user.uid), { status: newStatus });
    setStatus(newStatus);
  };

  const updateOrderStatus = async (id, newStatus) => {
    try {
      const reqRef = doc(db, "shopkeepers", user.uid, "print_requests", id);
      await updateDoc(reqRef, { status: newStatus });
    } catch (err) {
      console.error("Error updating status:", err);
    }
  };

  const intOrZero = val => {
    const i = parseInt(val);
    return isNaN(i) ? 0 : i;
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-2xl font-bold">📋 Print Requests</h2>
        <button onClick={() => signOut(auth)} className="bg-red-500 text-white px-4 py-2 rounded">Logout</button>
      </div>

      <div className="mb-6 p-4 bg-white rounded-lg shadow border border-gray-200">
        <h3 className="text-lg font-semibold mb-2">🔌 Service Availability</h3>
        <button
          onClick={toggleStatus}
          className={`px-4 py-2 rounded text-white ${status === "Available" ? "bg-green-600" : "bg-red-600"}`}
        >
          {status === "Available" ? "Turn OFF Service" : "Turn ON Service"}
        </button>
        <p className="mt-2 text-gray-700">
          Current Status: <strong>{status}</strong>
        </p>
      </div>

      {orders.length === 0 ? (
        <p>No print requests yet.</p>
      ) : (
        <div className="grid gap-4">
          {orders.map(order => {
            const settings = order.perPageSettings || [];
            return (
              <div key={order.id} className="bg-white rounded-xl shadow p-4 border border-gray-200">
                <div className="mb-2">
                  <strong>📦 Request ID:</strong> <code>{order.id}</code>
                </div>
                <div className="mb-2">
                  <strong>📄 File:</strong>{" "}
                  <a href={order.fileUrl} target="_blank" rel="noopener noreferrer" className="text-blue-500 underline">
                    View
                  </a>
                </div>
                <div className="mb-2">
                  <strong>Status:</strong> <span className="text-blue-600 font-semibold">{order.status}</span>
                </div>
                <div className="mb-2">
                  <strong>📅 Submitted:</strong> {order.timestamp ? new Date(order.timestamp.seconds * 1000).toLocaleString() : "Unknown"}
                </div>

                {/* Display per-page manual settings */}
                {settings.length > 0 && (
                  <div className="bg-gray-50 p-3 rounded-lg mb-3 border border-dashed">
                    <h4 className="font-semibold text-sm mb-2">🛠️ Per‑Page Settings:</h4>
                    {settings.map((s, idx) => (
                      <div key={idx} className="text-sm">
                        Page {s.page} &rarr; {s.type} ({s.copies} copies)
                      </div>
                    ))}
                  </div>
                )}

                {/* Batch summary */}
                <div className="bg-gray-50 p-3 rounded-lg mb-3 border border-dashed">
                  <h4 className="font-semibold text-sm mb-2">🧾 Batch Details:</h4>
                  <div className="bg-white border rounded px-3 py-2 mb-2 text-sm">
                    <div><strong>📄 Pages:</strong> {order.pages ?? "N/A"}</div>
                    <div><strong>🖨️ Copies:</strong> {order.copies ?? "N/A"}</div>
                    <div><strong>🎨 Color:</strong> {order.color ?? "N/A"}</div>
                    <div><strong>📑 Print Type:</strong> {order.printType ?? "N/A"}</div>
                    <div><strong>📚 Binding:</strong> {order.binding ? "Yes" : "No"}</div>
                    <div><strong>📌 Punch:</strong> {order.punch ? "Yes" : "No"}</div>
                    <div><strong>📎 Staple:</strong> {order.staple ? "Yes" : "No"}</div>
                    <div><strong>💰 Total Price:</strong> ₹{intOrZero(order.price)}</div>
                  </div>
                </div>

                <div className="flex gap-2">
                  {["In Queue", "Printing", "Ready"].map(st => (
                    <button
                      key={st}
                      className={`px-3 py-1 rounded text-white ${
                        st === "In Queue" ? "bg-yellow-400" : st === "Printing" ? "bg-blue-500" : "bg-green-600"
                      }`}
                      onClick={() => updateOrderStatus(order.id, st)}
                    >
                      {st}
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
